  { key: "valence", low: "Melancholy", high: "Sunlit" },
  { key: "intensity", low: "Gentle", high: "Ferocious" },
  { key: "eclecticism", low: "Focused", high: "Eclectic" },
  { key: "obscurity", low: "Mainstream", high: "Underground" },
  { key: "nostalgia", low: "Present", high: "Nostalgic" },
]

export function MoodSpectrumChart({ mood }: { mood: MoodSpectrum }) {
  return (
    <div className="space-y-4">
      {AXES.map(({ key, low, high }) => {
        const value = mood[key]
        return (
          <div key={key} className="space-y-1">
            <div className="flex justify-between text-xs text-muted-foreground">
              <span>{low}</span>
              <span className="font-medium uppercase tracking-wider text-foreground">
                {key}
              </span>
              <span>{high}</span>
            </div>
            <div className="relative h-3 bg-secondary rounded-full overflow-hidden">
              <div
                className="absolute inset-y-0 left-0 bg-gradient-to-r from-primary/40 to-primary"
                style={{ width: `${value * 100}%` }}
              />
              <div
                className="absolute top-1/2 -translate-y-1/2 w-3 h-3 rounded-full bg-foreground border-2 border-background"
                style={{ left: `calc(${value * 100}% - 6px)` }}
              />
            </div>
          </div>
        )
      })}
    </div>
  )
}

