// Fetch + analyze whenever token or range changes
useEffect(() => {
  if (!token) return
  setLoading(true)
  setError(null)
  ;(async () => {
    try {
      const [me, artistsRes, tracksRes] = await Promise.all([
        spotifyFetch<SpotifyUser>(token, "/me"),
        spotifyFetch<{ items: SpotifyArtist[] }>(
          token,
          `/me/top/artists?time_range=${range}&limit=30`,
        ),
        spotifyFetch<{ items: SpotifyTrack[] }>(
          token,
          `/me/top/tracks?time_range=${range}&limit=30`,
        ),
      ])
      setUser(me)
      const artists = artistsRes.items
      const tracks = tracksRes.items
      if (artists.length === 0 && tracks.length === 0) {
        setError("Spotify returned no listening history for this range yet. Try a longer window.")
        setInsight(null)
        return
      }
      const dna = buildGenreDNA(artists)
      const mood = buildMoodSpectrum(artists, tracks, dna)
      const archetype = classifyArchetype(dna, mood)
      const alterEgo = generateAlterEgo(archetype, dna)
      setInsight({ archetype, dna, mood, alterEgo, topArtists: artists, topTracks: tracks })
    } catch (e) {
      const msg = e instanceof Error ? e.message : "Unknown error"
      if (msg.includes("401")) {
        sessionStorage.clear()
        router.replace("/?spotify_error=session_expired")
      } else {
        setError(msg)
      }
    } finally {
      setLoading(false)
    }
  })()
}, [token, range, router])

