"use client"

import type { MoodSpectrum } from "@/lib/personality"

const AXES: { key: keyof MoodSpectrum; label: string; high: string }[] = [
  { key: "energy", label: "Energy", high: "Charged" },
  { key: "valence", label: "Valence", high: "Sunlit" },
  { key: "intensity", label: "Intensity", high: "Ferocious" },
  { key: "eclecticism", label: "Eclecticism", high: "Eclectic" },
  { key: "obscurity", label: "Obscurity", high: "Underground" },
  { key: "nostalgia", label: "Nostalgia", high: "Vintage" },
]

export function MoodRadar({ mood }: { mood: MoodSpectrum }) {
  const size = 360
  const cx = size / 2
  const cy = size / 2
  const radius = 130
  const n = AXES.length

  const point = (i: number, value: number) => {
    const angle = (Math.PI * 2 * i) / n - Math.PI / 2
    return {
      x: cx + Math.cos(angle) * radius * value,
      y: cy + Math.sin(angle) * radius * value,
    }
  }

  // Concentric reference rings at 25/50/75/100%
  const rings = [0.25, 0.5, 0.75, 1].map((r) =>
    AXES.map((_, i) => point(i, r))
      .map((p) => `${p.x},${p.y}`)
      .join(" "),
  )

  const polygon = AXES.map((axis, i) => point(i, mood[axis.key]))
    .map((p) => `${p.x},${p.y}`)
    .join(" ")

  return (
    <div className="flex flex-col md:flex-row items-center gap-8">
      <svg viewBox={`0 0 ${size} ${size}`} className="w-80 h-80 flex-shrink-0">
        {/* rings */}
        {rings.map((pts, i) => (
          <polygon
            key={i}
            points={pts}
            fill="none"
            stroke="currentColor"
            className="text-border"
            strokeWidth={1}
            opacity={0.4}
          />
        ))}
        {/* axes */}
        {AXES.map((axis, i) => {
          const end = point(i, 1)
          return (
            <line
              key={axis.key}
              x1={cx}
              y1={cy}
              x2={end.x}
              y2={end.y}
              stroke="currentColor"
              className="text-border"
              strokeWidth={1}
              opacity={0.4}
            />
          )
        })}
        {/* gradient fill for the shape */}
        <defs>
          <radialGradient id="moodFill" cx="50%" cy="50%" r="50%">
            <stop offset="0%" stopColor="#1DB954" stopOpacity={0.7} />
            <stop offset="100%" stopColor="#a855f7" stopOpacity={0.3} />
          </radialGradient>
        </defs>
        <polygon
          points={polygon}
          fill="url(#moodFill)"
          stroke="#1DB954"
          strokeWidth={2}
          strokeLinejoin="round"
        />
        {/* vertex dots */}
        {AXES.map((axis, i) => {
          const p = point(i, mood[axis.key])
          return (
            <circle
              key={axis.key}
              cx={p.x}
              cy={p.y}
              r={4}
              fill="#fff"
              stroke="#1DB954"
              strokeWidth={2}
            />
          )
        })}
        {/* labels */}
        {AXES.map((axis, i) => {
          const p = point(i, 1.18)
          const anchor =
            p.x < cx - 5 ? "end" : p.x > cx + 5 ? "start" : "middle"
          return (
            <g key={axis.key}>
              <text
                x={p.x}
                y={p.y}
                textAnchor={anchor}
                fontSize={12}
                fontWeight={600}
                fill="currentColor"
                className="text-foreground"
              >
                {axis.label}
              </text>
              <text
                x={p.x}
                y={p.y + 14}
                textAnchor={anchor}
                fontSize={10}
                fill="currentColor"
                className="text-muted-foreground"
              >
                {Math.round(mood[axis.key] * 100)}
              </text>
            </g>
          )
        })}
      </svg>
      <div className="flex-1 space-y-2 text-sm">
        {AXES.map((axis) => (
          <div key={axis.key} className="flex justify-between gap-3">
            <span className="text-muted-foreground">{axis.label}</span>
            <span className="font-medium">
              {Math.round(mood[axis.key] * 100)} / 100
              <span className="ml-2 text-xs text-muted-foreground">
                · {axis.high}
              </span>
            </span>
          </div>
        ))}
      </div>
    </div>
  )
}

